SELECT entity_type, MAX(overlap_value) AS max_overlap_value
FROM overlap_analysis
GROUP BY entity_type;

SELECT district_id, district_number, area
FROM congressional_districts
WHERE area > (SELECT AVG(area) FROM congressional_districts);

SELECT analysis_id, entity_type, entity_name, overlap_value, overlap_percentage, analysis_date 
FROM overlap_analysis 
WHERE district_id = 1;

SELECT state_id, COUNT(district_number) AS number_of_districts, SUM(registered_voters) AS total_registered_voters
FROM congressional_districts
GROUP BY state_id;

SELECT district_id, state_id, district_number, registered_voters
FROM congressional_districts
WHERE registered_voters = (SELECT MAX(registered_voters) FROM congressional_districts);

SELECT AVG(cd.registered_voters) AS Average_Voters
FROM congressional_districts cd
WHERE cd.state_id = (
    SELECT state_id 
    FROM states 
    WHERE registered_voters = (
        SELECT MAX(registered_voters) 
        FROM states
    )
);

SELECT district_id, district_number, state_id, chamber, area, population, registered_voters, district_type, created_at, updated_at
FROM congressional_districts
ORDER BY registered_voters DESC;

SELECT cd.district_number AS 'District Name', cd.registered_voters AS 'Total Voters'
FROM congressional_districts cd
ORDER BY cd.district_number;

SELECT s.state_name
FROM states s
WHERE s.population > (
  SELECT AVG(cd.population) AS avg_district_population
  FROM congressional_districts cd
);

SELECT analysis_id, district_id, entity_name, overlap_percentage
FROM overlap_analysis
WHERE overlap_percentage > 50;
